import{_ as i}from"./chunks/文件受限图.DsG20F9s.js";import{_ as a,o as r,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Görsel Moderasyonu ve Erişim Modu","description":"","frontmatter":{},"headers":[],"relativePath":"tr-TR/Safety/image-moderation-and-access-mode.md","filePath":"tr-TR/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),d={name:"tr-TR/Safety/image-moderation-and-access-mode.md"};function t(s,e,o,m,c,u){return r(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="gorsel-moderasyonu-ve-erisim-modu" tabindex="-1">Görsel Moderasyonu ve Erişim Modu <a class="header-anchor" href="#gorsel-moderasyonu-ve-erisim-modu" aria-label="Permalink to &quot;Görsel Moderasyonu ve Erişim Modu&quot;">​</a></h1><p>Görsel moderasyonu, yüklenen görsellere yaş derecelendirmesi atar. Erişim modu, hangi derecelendirmelerin herkese açık erişimde görüneceğini belirler.</p><p>Bu ayar public gallery, herkese açık dosya URL&#39;leri ve random image API üzerinde etkilidir. Yönetim panelini kısıtlamaz. Yöneticiler tüm dosyaları görmeye ve yönetmeye devam eder.</p><h2 id="nereden-yapılandırılır" tabindex="-1">Nereden Yapılandırılır? <a class="header-anchor" href="#nereden-yapılandırılır" aria-label="Permalink to &quot;Nereden Yapılandırılır?&quot;">​</a></h2><p>Yönetim panelini açın, ardından şuraya gidin:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>Ana ayarlar şunlardır:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="access-mode-ne-ise-yarar" tabindex="-1">Access Mode Ne İşe Yarar? <a class="header-anchor" href="#access-mode-ne-ise-yarar" aria-label="Permalink to &quot;Access Mode Ne İşe Yarar?&quot;">​</a></h2><p>Access mode, hangi yaş derecelendirmelerinin herkese açık gösterilebileceğini belirler.</p><p>Geçerli modlar:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Herkese Açık Görünen Derecelendirmeler</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>Yalnızca General</td></tr></tbody></table><p>Varsayılan Adult mode değeridir.</p><p>Özel siteler veya yetişkin içerikli siteler için Adult mode uygun olabilir. Daha kontrollü bir public gallery için Youth, Teen veya Child mode seçin.</p><h2 id="moderasyonu-etkinlestirmek-ne-saglar" tabindex="-1">Moderasyonu Etkinleştirmek Ne Sağlar? <a class="header-anchor" href="#moderasyonu-etkinlestirmek-ne-saglar" aria-label="Permalink to &quot;Moderasyonu Etkinleştirmek Ne Sağlar?&quot;">​</a></h2><p>Moderasyon etkin olduğunda ImgBed yükleme sırasında seçili moderation provider&#39;ı çağırır ve algılanan yaş derecelendirmesini kaydeder.</p><p>Ana derecelendirmeler:</p><table tabindex="0"><thead><tr><th>Derecelendirme</th><th>Anlamı</th></tr></thead><tbody><tr><td>General</td><td>Güvenli herkese açık içerik</td></tr><tr><td>R12</td><td>Hafif hassas içerik</td></tr><tr><td>R16</td><td>Orta düzey hassas içerik</td></tr><tr><td>R18</td><td>Yetişkin içerik</td></tr></tbody></table><p>Moderasyon sonucu herkese açık erişime karar verirken kullanılır.</p><p>Moderasyon etkin değilse veya eski dosyaların derecelendirmesi yoksa bu dosyalar unrated kabul edilir. Unrated dosyalar yalnızca derecelendirme olmadığı için public gallery veya random image API&#39;den otomatik kaldırılmaz.</p><h2 id="moderation-provider-secimi" tabindex="-1">Moderation Provider Seçimi <a class="header-anchor" href="#moderation-provider-secimi" aria-label="Permalink to &quot;Moderation Provider Seçimi&quot;">​</a></h2><p>Kullanılabilir sağlayıcılar:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>Her sağlayıcının gereksinimi farklıdır:</p><ul><li>moderatecontent.com genellikle API Key ister.</li><li>nsfwjs genellikle API endpoint URL ister.</li><li>Sightengine API user ve API secret ister.</li></ul><p>Hesabınıza, erişilebilirliğe ve algılama kalitesine göre seçin. Moderasyon etkin ve doğru yapılandırılmışsa ImgBed yükleme sırasında görsel derecelendirmesi yazmaya çalışır.</p><h2 id="public-gallery-uzerindeki-etkisi" tabindex="-1">Public Gallery Üzerindeki Etkisi <a class="header-anchor" href="#public-gallery-uzerindeki-etkisi" aria-label="Permalink to &quot;Public Gallery Üzerindeki Etkisi&quot;">​</a></h2><p>Public gallery dosyaları access mode değerine göre filtreler.</p><p>Örnekler:</p><ul><li>Adult mode: R18 görseller görünebilir.</li><li>Youth mode: R18 görseller gizlenir.</li><li>Teen mode: R16 ve R18 görseller gizlenir.</li><li>Child mode: yalnızca General görseller gösterilir.</li></ul><p>Bu yalnızca normal herkese açık erişimi etkiler. Yönetim paneli tüm dosyaları göstermeye devam eder.</p><h2 id="herkese-acık-dosya-url-leri-uzerindeki-etkisi" tabindex="-1">Herkese Açık Dosya URL&#39;leri Üzerindeki Etkisi <a class="header-anchor" href="#herkese-acık-dosya-url-leri-uzerindeki-etkisi" aria-label="Permalink to &quot;Herkese Açık Dosya URL&#39;leri Üzerindeki Etkisi&quot;">​</a></h2><p>Herkese açık dosya URL&#39;leri, ziyaretçilerin açtığı doğrudan görsel bağlantılarıdır.</p><p>Dosyanın derecelendirmesi geçerli access mode tarafından izin verilen düzeydeyse ImgBed özgün görseli döndürür.</p><p>Derecelendirme izin verilen seviyenin üzerindeyse normal herkese açık erişim özgün görseli döndürmez. Bunun yerine ImgBed yapılandırılmış blocked result veya yer tutucu görsel döndürür.</p><p>Örnek:</p><ul><li>Geçerli mod Child mode.</li><li>Görsel R18 olarak derecelendirilmiş.</li><li>Ziyaretçi herkese açık URL&#39;yi doğrudan açıyor.</li><li>ImgBed bu ziyaretçiye R18 özgün görseli döndürmez.</li></ul><p><img src="'+i+'" alt="Kısıtlanmış dosya görseli" loading="lazy"></p><p>Yönetim panelinde dosyaları görüntüleyen yöneticiler bu kısıtlamadan etkilenmez.</p><h2 id="random-image-api-uzerindeki-etkisi" tabindex="-1">Random Image API Üzerindeki Etkisi <a class="header-anchor" href="#random-image-api-uzerindeki-etkisi" aria-label="Permalink to &quot;Random Image API Üzerindeki Etkisi&quot;">​</a></h2><p>Random image API de aday havuzunu access mode değerine göre filtreler.</p><p>Child mode içinde rastgele görseller yalnızca General dereceli dosyalardan seçilir.</p><p>Youth mode içinde rastgele görseller General, R12 ve R16 dosyalardan gelebilir; R18 dosyalar dahil edilmez.</p><p>Bu, random image API&#39;nin public gallery kısıtlamalarını aşmasını engeller.</p><h2 id="liste-kurallarıyla-iliskisi" tabindex="-1">Liste Kurallarıyla İlişkisi <a class="header-anchor" href="#liste-kurallarıyla-iliskisi" aria-label="Permalink to &quot;Liste Kurallarıyla İlişkisi&quot;">​</a></h2><p>Access mode tek herkese açık erişim kuralı değildir. Allow/block list kurallarıyla birlikte çalışır.</p><p>Basitçe:</p><ul><li>Allowlist içeriği önce public kabul edilir.</li><li>Blocklist içeriği normal ziyaretçiler tarafından doğrudan görüntülenemez.</li><li>İki listede de olmayan içerik ardından access mode ile kontrol edilir.</li></ul><p>Bir görsel hem yaş derecelendirmesi hem liste kurallarıyla kısıtlanmışsa normal ziyaretçiler özgün dosyayı yine doğrudan göremez.</p><h2 id="onerilen-ayarlar" tabindex="-1">Önerilen Ayarlar <a class="header-anchor" href="#onerilen-ayarlar" aria-label="Permalink to &quot;Önerilen Ayarlar&quot;">​</a></h2><p>Herkese açık siteler için:</p><ul><li>Moderasyonu etkinleştirin.</li><li>Sitenin hedef kitlesine uygun access mode seçin.</li><li>Her yaş grubuna açık ziyaretçiler için Child mode veya Teen mode kullanın.</li><li>Yetişkin içeriğin herkese açık görünmesini istemiyorsanız Adult mode kullanmaktan kaçının.</li><li>Yönetim panelindeki dosya derecelendirmelerini inceleyip gerektiğinde elle düzeltin.</li></ul><p>Özel veya kişisel siteler için:</p><ul><li>Adult mode genellikle uygundur.</li><li>İşinize yarıyorsa moderasyonu etkinleştirin.</li><li>Yönetim panelinde derecelendirmeleri gerektiğinde inceleyip düzeltin.</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="access-mode-degistirince-dosyalar-yonetim-panelinden-kaybolur-mu" tabindex="-1">Access Mode Değiştirince Dosyalar Yönetim Panelinden Kaybolur mu? <a class="header-anchor" href="#access-mode-degistirince-dosyalar-yonetim-panelinden-kaybolur-mu" aria-label="Permalink to &quot;Access Mode Değiştirince Dosyalar Yönetim Panelinden Kaybolur mu?&quot;">​</a></h3><p>Hayır.</p><p>Access mode yalnızca normal herkese açık erişimi etkiler. Yönetim panelini etkilemez.</p><h3 id="child-mode-a-gecince-public-gallery-neden-daha-az-gorsel-gosterdi" tabindex="-1">Child Mode&#39;a Geçince Public Gallery Neden Daha Az Görsel Gösterdi? <a class="header-anchor" href="#child-mode-a-gecince-public-gallery-neden-daha-az-gorsel-gosterdi" aria-label="Permalink to &quot;Child Mode&#39;a Geçince Public Gallery Neden Daha Az Görsel Gösterdi?&quot;">​</a></h3><p>Child mode yalnızca General dereceli dosyaların herkese açık gösterilmesine izin verir. R12, R16 ve R18 dosyalar filtrelenir.</p><h3 id="herkese-acık-url-ler-adult-images-acabilir-mi" tabindex="-1">Herkese Açık URL&#39;ler Adult Images Açabilir mi? <a class="header-anchor" href="#herkese-acık-url-ler-adult-images-acabilir-mi" aria-label="Permalink to &quot;Herkese Açık URL&#39;ler Adult Images Açabilir mi?&quot;">​</a></h3><p>Geçerli access mode bu derecelendirmeye izin vermiyorsa normal herkese açık URL&#39;ler özgün görseli döndürmez.</p><h3 id="random-image-api-kısıtlı-gorseller-dondurebilir-mi" tabindex="-1">Random Image API Kısıtlı Görseller Döndürebilir mi? <a class="header-anchor" href="#random-image-api-kısıtlı-gorseller-dondurebilir-mi" aria-label="Permalink to &quot;Random Image API Kısıtlı Görseller Döndürebilir mi?&quot;">​</a></h3><p>Hayır.</p><p>Random image API adayları geçerli access mode değerine göre filtreler.</p><h3 id="eski-unrated-images-ne-olur" tabindex="-1">Eski Unrated Images Ne Olur? <a class="header-anchor" href="#eski-unrated-images-ne-olur" aria-label="Permalink to &quot;Eski Unrated Images Ne Olur?&quot;">​</a></h3><p>Unrated görseller yalnızca moderasyon sonucu olmadığı için otomatik gizlenmez. Derecelendirmelerini daha sonra yönetim panelinde değiştirebilirsiniz.</p>',67)])])}const p=a(d,[["render",t]]);export{h as __pageData,p as default};
